// Heat-scale interpolation 0..40 mbar → blue → cyan → green → orange → red
function dpColor(v) {
  if (v===null || v===undefined || isNaN(v)) return '#1e3a5f';
  var stops = [
    {p:0,   c:[30,58,95]},     // #1e3a5f
    {p:10,  c:[34,211,238]},   // #22d3ee
    {p:20,  c:[34,197,94]},    // #22c55e
    {p:30,  c:[245,158,11]},   // #f59e0b
    {p:40,  c:[239,68,68]}     // #ef4444
  ];
  var x = Math.max(0, Math.min(40, v));
  for (var i = 0; i < stops.length - 1; i++) {
    if (x <= stops[i+1].p) {
      var a = stops[i], b = stops[i+1];
      var t = (x - a.p) / (b.p - a.p);
      var r = Math.round(a.c[0] + (b.c[0]-a.c[0])*t);
      var g = Math.round(a.c[1] + (b.c[1]-a.c[1])*t);
      var bl= Math.round(a.c[2] + (b.c[2]-a.c[2])*t);
      return 'rgb(' + r + ',' + g + ',' + bl + ')';
    }
  }
  return '#ef4444';
}

